document.addEventListener("DOMContentLoaded",function(){const form=document.getElementById("resetPasswordForm");const btnSubmit=document.getElementById("btn-submit");const spinner=btnSubmit.querySelector(".spinner");const urlParams=new URLSearchParams(window.location.search);const token=urlParams.get("token");if(!token){document.querySelector('[data-for="general"]').textContent="Lien invalide ou manquant.";return}
const tokenInput=document.getElementById("token-input");if(tokenInput){tokenInput.value=token}else{}
function showError(field,message){const errorEl=document.querySelector(`[data-for="${field}"]`);if(errorEl){errorEl.textContent=message;errorEl.style.opacity="1"}}
function clearError(field){const errorEl=document.querySelector(`[data-for="${field}"]`);if(errorEl){errorEl.textContent="";errorEl.style.opacity="0"}}
document.getElementById("new-password").addEventListener("input",()=>clearError("new-password"));document.getElementById("confirm-password").addEventListener("input",()=>clearError("confirm-password"));function showToast(message,type="success"){let container=document.getElementById("toast-container");if(!container){container=document.createElement("div");container.id="toast-container";document.body.appendChild(container)}
const toast=document.createElement("div");toast.className=`toast ${type}`;toast.textContent=message;container.appendChild(toast);setTimeout(()=>toast.classList.add("show"),100);setTimeout(()=>{toast.classList.remove("show");setTimeout(()=>toast.remove(),300)},4000)}
form.addEventListener("submit",function(e){e.preventDefault();document.querySelectorAll(".error-message").forEach(el=>{el.textContent="";el.style.opacity="0"});const newPassword=document.getElementById("new-password").value.trim();const confirmPassword=document.getElementById("confirm-password").value.trim();let hasError=!1;if(!newPassword){showError("new-password","Veuillez entrer un nouveau mot de passe.");hasError=!0}else if(newPassword.length<8){showError("new-password","Le mot de passe doit faire au moins 8 caractères.");hasError=!0}
if(!confirmPassword){showError("confirm-password","Veuillez confirmer le mot de passe.");hasError=!0}else if(newPassword!==confirmPassword){showError("confirm-password","Les mots de passe ne correspondent pas.");hasError=!0}
if(hasError){return}
spinner.style.display="inline-block";btnSubmit.disabled=!0;const formData=new FormData(form);fetch("./reset-password",{method:"POST",body:formData}).then(response=>{if(!response.ok){throw new Error(`HTTP ${response.status} - ${response.statusText}`)}
return response.text()}).then(text=>{let data;try{data=JSON.parse(text)}catch(parseError){throw new Error("Réponse du serveur non JSON")}
spinner.style.display="none";btnSubmit.disabled=!1;if(data.success){showToast("Mot de passe réinitialisé avec succès !","success");setTimeout(()=>location.href="./login",2000)}else{const msg=data.message||"Une erreur est survenue.";document.querySelector('[data-for="general"]').textContent=msg;showToast(msg,"error")}}).catch(err=>{spinner.style.display="none";btnSubmit.disabled=!1;document.querySelector('[data-for="general"]').textContent="Erreur de connexion au serveur.";showToast("Erreur réseau ou serveur. Réessayez.","error")})})})